package com.nuvo.backend.features.order.service

import com.nuvo.backend.features.catalog.repository.SKURepository
import com.nuvo.backend.features.order.domain.Cart
import com.nuvo.backend.features.order.domain.CartItem
import com.nuvo.backend.features.order.dto.AddToCartRequest
import com.nuvo.backend.features.order.dto.CartDTO
import com.nuvo.backend.features.order.dto.CartItemDTO
import com.nuvo.backend.features.order.repository.CartRepository
import com.nuvo.backend.features.user.repository.UserRepository
import org.springframework.stereotype.Service
import org.springframework.transaction.annotation.Transactional
import java.math.BigDecimal
import java.time.LocalDateTime
import java.util.*

@Service
class CartService(
    private val cartRepository: CartRepository,
    private val userRepository: UserRepository,
    private val skuRepository: SKURepository
) {

    @Transactional
    fun getOrCreateCart(firebaseUid: String): Cart {
        val user = userRepository.findByFirebaseUid(firebaseUid) ?: throw Exception("User not found")
        return cartRepository.findByUserId(user.id) ?: cartRepository.save(Cart(user = user))
    }

    @Transactional
    fun addItemToCart(firebaseUid: String, request: AddToCartRequest): CartDTO {
        val cart = getOrCreateCart(firebaseUid)
        val sku = skuRepository.findById(request.skuId).orElseThrow { Exception("SKU not found") }
        val store = sku.product.store

        // Single Store Rule
        if (cart.store != null && cart.store?.id != store.id) {
            cart.items.clear()
        }
        cart.store = store

        val existingItem = cart.items.find { it.sku.id == sku.id }
        if (existingItem != null) {
            existingItem.quantity += request.quantity
            existingItem.updatedAt = LocalDateTime.now()
        } else {
            cart.items.add(CartItem(cart = cart, sku = sku, quantity = request.quantity))
        }

        cart.updatedAt = LocalDateTime.now()
        return cartRepository.save(cart).toDTO()
    }

    @Transactional
    fun updateItemQuantity(firebaseUid: String, itemId: UUID, quantity: Int): CartDTO {
        val cart = getOrCreateCart(firebaseUid)
        val item = cart.items.find { it.id == itemId } ?: throw Exception("Item not found in cart")

        if (quantity <= 0) {
            cart.items.remove(item)
        } else {
            item.quantity = quantity
            item.updatedAt = LocalDateTime.now()
        }

        if (cart.items.isEmpty()) {
            cart.store = null
        }

        cart.updatedAt = LocalDateTime.now()
        return cartRepository.save(cart).toDTO()
    }

    @Transactional
    fun clearCart(firebaseUid: String) {
        val cart = getOrCreateCart(firebaseUid)
        cart.items.clear()
        cart.store = null
        cart.updatedAt = LocalDateTime.now()
        cartRepository.save(cart)
    }

    fun getCartDTO(firebaseUid: String): CartDTO {
        return getOrCreateCart(firebaseUid).toDTO()
    }

    private fun Cart.toDTO(): CartDTO {
        val itemDTOs = items.map { it.toDTO() }
        val total = itemDTOs.sumOf { it.subTotal }
        return CartDTO(id, store?.id, itemDTOs, total)
    }

    private fun CartItem.toDTO(): CartItemDTO {
        val price = sku.discountedPrice ?: sku.originalPrice
        return CartItemDTO(
            id = id,
            skuId = sku.id,
            skuName = sku.name,
            quantity = quantity,
            price = price,
            subTotal = price.multiply(BigDecimal(quantity))
        )
    }
}

package com.nuvo.backend.features.order.service

import com.fasterxml.jackson.databind.ObjectMapper
import com.nuvo.backend.features.order.domain.Order
import com.nuvo.backend.features.order.domain.OrderItem
import com.nuvo.backend.features.order.domain.OrderStatus
import com.nuvo.backend.features.order.dto.CheckoutRequest
import com.nuvo.backend.features.order.dto.OrderDTO
import com.nuvo.backend.features.order.dto.OrderItemDTO
import com.nuvo.backend.features.order.repository.OrderRepository
import com.nuvo.backend.features.user.repository.UserAddressRepository
import com.nuvo.backend.features.user.repository.UserRepository
import org.springframework.data.domain.Page
import org.springframework.data.domain.Pageable
import org.springframework.stereotype.Service
import org.springframework.transaction.annotation.Transactional
import java.math.BigDecimal
import java.util.*

@Service
class OrderService(
    private val cartService: CartService,
    private val orderRepository: OrderRepository,
    private val userRepository: UserRepository,
    private val addressRepository: UserAddressRepository,
    private val objectMapper: ObjectMapper
) {

    @Transactional
    fun checkout(firebaseUid: String, request: CheckoutRequest): OrderDTO {
        val user = userRepository.findByFirebaseUid(firebaseUid) ?: throw Exception("User not found")
        val cart = cartService.getOrCreateCart(firebaseUid)

        if (cart.items.isEmpty()) throw Exception("Cart is empty")
        val store = cart.store ?: throw Exception("Cart has no store assigned")

        val address = addressRepository.findById(request.addressId)
            .filter { it.user.id == user.id }
            .orElseThrow { Exception("Address not found") }

        // Snapshot address to JSON
        val addressSnapshot = objectMapper.writeValueAsString(
            mapOf(
                "title" to address.title,
                "fullAddress" to address.fullAddress,
                "latitude" to address.location.y,
                "longitude" to address.location.x
            )
        )

        val totalAmount = cart.items.sumOf { 
            (it.sku.discountedPrice ?: it.sku.originalPrice).multiply(BigDecimal(it.quantity)) 
        }

        val order = Order(
            user = user,
            store = store,
            totalAmount = totalAmount,
            deliveryAddressSnapshot = addressSnapshot
        )

        cart.items.forEach { cartItem ->
            val price = cartItem.sku.discountedPrice ?: cartItem.sku.originalPrice
            order.items.add(
                OrderItem(
                    order = order,
                    sku = cartItem.sku,
                    snapshotPrice = price,
                    quantity = cartItem.quantity
                )
            )
        }

        val savedOrder = orderRepository.save(order)
        cartService.clearCart(firebaseUid)

        return savedOrder.toDTO()
    }

    fun getOrderHistory(firebaseUid: String, pageable: Pageable): Page<OrderDTO> {
        val user = userRepository.findByFirebaseUid(firebaseUid) ?: throw Exception("User not found")
        return orderRepository.findAllByUserIdOrderByCreatedAtDesc(user.id, pageable).map { it.toDTO() }
    }

    fun getOrderDetails(firebaseUid: String, orderId: UUID): OrderDTO {
        val user = userRepository.findByFirebaseUid(firebaseUid) ?: throw Exception("User not found")
        val order = orderRepository.findById(orderId).orElseThrow { Exception("Order not found") }
        if (order.user?.id != user.id) throw Exception("Unauthorized")
        return order.toDTO()
    }

    private fun Order.toDTO() = OrderDTO(
        id = id,
        storeId = store?.id ?: UUID.randomUUID(), // Should not happen with validation
        status = status,
        totalAmount = totalAmount,
        deliveryAddressSnapshot = deliveryAddressSnapshot,
        items = items.map { it.toDTO() },
        createdAt = createdAt.toString()
    )

    private fun OrderItem.toDTO() = OrderItemDTO(
        skuId = sku?.id,
        skuName = sku?.name,
        snapshotPrice = snapshotPrice,
        quantity = quantity
    )
}

