import java.math.BigDecimal
import java.time.LocalDateTime
import java.util.*

@Service
class CartService(
    private val cartRepository: CartRepository,
    private val userRepository: UserRepository,
    private val skuRepository: SKURepository
) {

    @Transactional
    fun getOrCreateCart(firebaseUid: String): Cart {
        val user = userRepository.findByFirebaseUid(firebaseUid) ?: throw Exception("User not found")
        return cartRepository.findByUserId(user.id) ?: cartRepository.save(Cart(user = user))
    }

    @Transactional
    fun addItemToCart(firebaseUid: String, request: AddToCartRequest): CartDTO {
        val cart = getOrCreateCart(firebaseUid)
        val sku = skuRepository.findById(request.skuId).orElseThrow { Exception("SKU not found") }
        val store = sku.product.store

        // Single Store Rule
        if (cart.store != null && cart.store?.id != store.id) {
            cart.items.clear()
        }
        cart.store = store

        val existingItem = cart.items.find { it.sku.id == sku.id }
        if (existingItem != null) {
            existingItem.quantity += request.quantity
            existingItem.updatedAt = LocalDateTime.now()
        } else {
            cart.items.add(CartItem(cart = cart, sku = sku, quantity = request.quantity))
        }

        cart.updatedAt = LocalDateTime.now()
        return cartRepository.save(cart).toDTO()
    }

    @Transactional
    fun updateItemQuantity(firebaseUid: String, itemId: UUID, quantity: Int): CartDTO {
        val cart = getOrCreateCart(firebaseUid)
        val item = cart.items.find { it.id == itemId } ?: throw Exception("Item not found in cart")

        if (quantity <= 0) {
            cart.items.remove(item)
        } else {
            item.quantity = quantity
            item.updatedAt = LocalDateTime.now()
        }

