import jakarta.persistence.*
import java.math.BigDecimal
import java.time.LocalDateTime
import java.util.*

enum class OrderStatus {
    PENDING, PREPARING, DISPATCHED, DELIVERED, CANCELLED
}

@Entity
@Table(name = "orders")
@EntityListeners(AuditingEntityListener::class)
class Order(
    @Id
    @GeneratedValue(strategy = GenerationType.UUID)
    @UuidGenerator
    val id: UUID? = null,

    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "user_id")
    val user: User?,

    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "store_id", nullable = false)
    val store: Store?,

    @Enumerated(EnumType.STRING)
    @Column(nullable = false)
    var status: OrderStatus = OrderStatus.PENDING,

    @Column(name = "total_amount", nullable = false)
    val totalAmount: BigDecimal,

    @Column(name = "delivery_address_snapshot", columnDefinition = "jsonb", nullable = false)
    val deliveryAddressSnapshot: String,

    @OneToMany(mappedBy = "order", cascade = [CascadeType.ALL])
    val items: MutableList<OrderItem> = mutableListOf(),

    @CreatedDate
    @Column(name = "created_at", updatable = false)
    var createdAt: LocalDateTime? = null,

    @LastModifiedDate
    @Column(name = "updated_at")
    var updatedAt: LocalDateTime? = null
)

@Entity
@Table(name = "order_items")
@EntityListeners(AuditingEntityListener::class)
class OrderItem(
    @Id
    @GeneratedValue(strategy = GenerationType.UUID)
    @UuidGenerator
    val id: UUID? = null,

    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "order_id", nullable = false)
    val order: Order,

    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "sku_id")
    val sku: SKU?,

    @Column(name = "snapshot_price", nullable = false)
    val snapshotPrice: BigDecimal,

    @Column(nullable = false)
    val quantity: Int,

    @CreatedDate
    @Column(name = "created_at", updatable = false)
    var createdAt: LocalDateTime? = null
)

